const l=JSON.parse('{"key":"v-1fbc1360","path":"/bookList/Electrical%20Engineering%20101/six.html","title":"","lang":"zh-CN","frontmatter":{},"headers":[{"level":2,"title":"# 第六章 排除问题","slug":"第六章-排除问题","link":"#第六章-排除问题","children":[]}],"git":{},"readingTime":{"minutes":0.83,"words":248},"filePathRelative":"bookList/Electrical Engineering 101/six.md","excerpt":"<h2>  第六章 排除问题</h2>\\n<ul>\\n<li>\\n<ol>\\n<li>先排除简单的问题</li>\\n</ol>\\n</li>\\n</ul>\\n<p>如果排查问题之前，你不用线检查最简单的东西，那么你最后一定会很懊悔。</p>\\n<ul>\\n<li>\\n<ol start=\\"2\\">\\n<li>跳出专业看问题，</li>\\n</ol>\\n</li>\\n</ul>\\n<p>有些东西也许就只是简简单单的不是专业的问题，这个需要自己的潜意识里面知道。</p>\\n<ul>\\n<li>\\n<ol start=\\"3\\">\\n<li>注意细节</li>\\n</ol>\\n</li>\\n</ul>\\n<p>这里补充一个感觉比较实用的技巧。 如果一个东西是铁磁的，那么它导电的可能性很大。</p>"}');export{l as data};
